    },
    getConfig () {
      getSetting().then((response) => {
        if (response.status == 200) {
          this.form = response.data.data
        }
      })
    },
    onSubmit () {
      this.loading = true
      let query = {
        ...this.form
      }
      setSetting(query)
        .then((response) => {
          this.$message({
            type: 'success',
            message: '儲存成功'
          })
          this.getConfig()
          this.loading = false
        })
        .catch((error) => {
          this.loading = false
        })
    }
  }
